#!/usr/bin/env bash
# run-a-complete-discovery-call.sh — Run a complete discovery call（跑一个完整的需求挖掘电话） SOP walkthrough for B2B 大客户销售.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="B2B 大客户销售"
WORKFLOW="Run a complete discovery call（跑一个完整的需求挖掘电话）"

usage() {
  cat <<EOF
run-a-complete-discovery-call.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./run-a-complete-discovery-call.sh             # interactive
  ./run-a-complete-discovery-call.sh --dry-run
  ./run-a-complete-discovery-call.sh --json
  ./run-a-complete-discovery-call.sh --explain
  ./run-a-complete-discovery-call.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Run a complete discovery call（跑一个完整的需求挖掘电话）" 工作流。

一句话: Take a booked-but-unqualified meeting and leave with a *diagnosed, quantified business problem* + a locked next step — the single highest-leverage rep skill, and the one most often skipped in favor of a product pitch. (evidence: [T03-S001, T03-S003])

入门 SOP 共 5 步, 失败模式自检 4 项。

相关心智模型:
  • 问 ⇄ 教 ⇄ 筛:三派第一性张力,资深人按层混用: 复杂销售的方法论分三派——诊断式提问(SPIN/Gap:「客户有答案,问到痛点不可否认为止」)⇄ 挑战式教学(Challenger:「客户对自己问题的认知是错的,用商业洞见 reframe」)⇄ 资格
  • 头号对手是「不决策」,不是竞品: 预测内丢单的最大去向不是输给对手,而是客户「什么都不做」——维持现状;且一旦购买意向形成,买方更怕「搞砸」(FOMU)而非「错过」(FOMO),所以晚期停滞要按「犹豫」处理(去风险),不是按「异议」处

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**Set an agenda / up-front contract (PPO)** — open by agreeing Purpose / Plan / Outcome: \"the goal is to see if we *can* help or not… by the end let's have a frank discussion on fit.\" Sets the expectation this is not a product dump and earns permission to ask. (who: rep; output: buyer buy-in, no \"just show me a demo\" interruption). (evidence: [T03-S001, T03-S004])"
  "**Find the situation** — \"I'm sure you don't take every cold call — what prompted you to take this one?\" Surfaces why *now*. (evidence: [T03-S001])"
  "**Turn situation into a problem** — use \"typically\" framing (\"typically when someone's in your spot it's because A or B — which is it?\") + Sandler pain-funnel nesting (vague → specific → consequence). (evidence: [T03-S001, T03-S003])"
  "**Quantify the impact** — \"magic moment\" / implication questions (\"when did you realize this was a problem? what's it costing?\") drive vague frustration to a dollar figure the buyer says out loud. (evidence: [T03-S001, T03-S003])"
  "**Lock the next step (the \"5-minute drill\")** — pressure-test intent (\"is it worth continuing to invest time together?\"), get a timeline (\"latest you'd want this in place?\"), and *suggest* (don't ask) the next-next step aligned to how they buy. Only advance deals with genuine near-term (≈6-month) intent. (evidence: [T03-S001])"
)
declare -a FAILURE_MODES=(
  "**No up-front contract → the call gets hijacked into a demo**: the buyer drives, the rep pitches blind, no problem surfaces. Avoid: open every call agreeing Purpose/Plan/Outcome before any question. (evidence: [T03-S001])"
  "**Accepting vague pain (\"things could be more efficient\") without quantifying → no business case**: later you can't justify budget or beat a cheaper competitor. Avoid: stack implication questions until the buyer states a dollar/time cost out loud. (evidence: [T03-S003])"
  "**\"Show up and throw up\" — rep talks >50% of the call**: data shows won deals have the rep talking less (~43%). Avoid: ask, shut up, let silence work. (evidence: [T03-S031])"
  "**Ending with no dated next step (\"I'll send some info\")**: the deal has no forward motion and can't be forecast. Avoid: run the 5-minute drill — intent, timeline, suggested next-next step. (evidence: [T03-S001])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "run-a-complete-discovery-call-walkthrough"
fi
